for (const item of $input.all()) {
  const data = item.json;

  // 1. Format Phone Number
  if (data["Phone Numbers"]) {
    let p = data["Phone Numbers"].toString().trim();
    data["formattedPhone"] = p.startsWith('+') ? p : (p.startsWith('44') ? '+' + p : '+44' + p);
  }

  // 2. Format Date
  if (typeof data["Date Added"] === 'number') {
    data["formattedDate"] = new Date(Math.round((data["Date Added"] - 25569) * 86400 * 1000)).toISOString().split('T')[0];
  }

  // 3. Clean up Name and Company for JSON (remove quotes/newlines)
  const cleanName = (data["Full Name"] || "the customer").replace(/"/g, "'").replace(/\n/g, " ");
  const cleanCompany = (data["Company"] || "their company").replace(/"/g, "'").replace(/\n/g, " ");

  // 4. Create TwiML using SINGLE QUOTES for attributes
  data["debbieTwiML"] = `<Say voice='Polly.Amy'>Hello Debbie, you have a lead on the line named ${cleanName} from ${cleanCompany}. Press 1 to accept.</Say><Gather numDigits='1' timeout='10'><Say>Press 1 now.</Say></Gather>`;

  data["meetaTwiML"] = `<Say voice='Polly.Amy'>Hello Meeta, Debbie was unavailable. The caller is ${cleanName} from ${cleanCompany}. Press 1 to connect.</Say><Gather numDigits='1' timeout='10'><Say>Press 1 now.</Say></Gather>`;
}
return $input.all();

